const execId = $execution.id;
const store = $getWorkflowStaticData('global');
if (!store[execId]) store[execId] = {};
const myData = store[execId];
myData.results = [];

const body = $('Webhook').first().json.body;
const maxResults = Math.min(parseInt(body.max_results) || 20, 60);
const maxPages = Math.ceil(maxResults / 20);
const textQuery = body.business_type + ' in ' + body.location;

const firstPage = $input.first().json;
const places = (firstPage.places || []).map(p => ({
  place_id: p.id,
  name: p.displayName?.text || '',
  address: p.formattedAddress || '',
  phone: p.nationalPhoneNumber || '',
  website: !/facebook\.com|instagram\.com|(?:twitter|x)\.com/i.test(p.websiteUri || '') ? (p.websiteUri || '') : '',
  facebook: /facebook\.com/i.test(p.websiteUri || '') ? p.websiteUri : '',
  instagram: /instagram\.com/i.test(p.websiteUri || '') ? p.websiteUri : '',
  twitter: /(twitter|x)\.com/i.test(p.websiteUri || '') ? p.websiteUri : '',
  business_status: p.businessStatus || '',
  opening_hours: (p.regularOpeningHours?.weekdayDescriptions || []).join(' | '),
  price_level: p.priceLevel !== undefined ? String(p.priceLevel) : '',
  rating: p.rating !== undefined ? String(p.rating) : '',
  user_ratings_total: p.userRatingCount !== undefined ? String(p.userRatingCount) : '',
  types: Array.isArray(p.types) ? p.types.filter(t => t !== 'point_of_interest' && t !== 'establishment').join(', ') : '',
  reviews: (p.reviews || []).map(r => typeof r.text === 'object' ? (r.text.text || '') : (r.text || '')).filter(Boolean)
}));

const nextToken = firstPage.nextPageToken || null;

myData.textQuery = textQuery;
myData.newPlaces = places;
myData.nextToken = nextToken;
myData.maxResults = maxResults;
myData.pagesRemaining = Math.max(0, maxPages - 1);

return [{ json: {
  place_count: places.length,
  has_more: !!nextToken && maxPages > 1,
  pages_remaining: myData.pagesRemaining,
  next_page_token: nextToken,
  text_query: textQuery
}}];

const execId = $execution.id;
const store = $getWorkflowStaticData('global');
const myData = store[execId] || {};

const page = $input.first().json;

if (page.places && page.places.length > 0) {
  const newPlaces = page.places.map(p => ({
    place_id: p.id,
    name: p.displayName?.text || '',
    address: p.formattedAddress || '',
    phone: p.nationalPhoneNumber || '',
    website: !/facebook\.com|instagram\.com|(?:twitter|x)\.com/i.test(p.websiteUri || '') ? (p.websiteUri || '') : '',
    facebook: /facebook\.com/i.test(p.websiteUri || '') ? p.websiteUri : '',
    instagram: /instagram\.com/i.test(p.websiteUri || '') ? p.websiteUri : '',
    twitter: /(twitter|x)\.com/i.test(p.websiteUri || '') ? p.websiteUri : '',
    business_status: p.businessStatus || '',
    opening_hours: (p.regularOpeningHours?.weekdayDescriptions || []).join(' | '),
    price_level: p.priceLevel !== undefined ? String(p.priceLevel) : '',
    rating: p.rating !== undefined ? String(p.rating) : '',
    user_ratings_total: p.userRatingCount !== undefined ? String(p.userRatingCount) : '',
    types: Array.isArray(p.types) ? p.types.filter(t => t !== 'point_of_interest' && t !== 'establishment').join(', ') : '',
    reviews: (p.reviews || []).map(r => typeof r.text === 'object' ? (r.text.text || '') : (r.text || '')).filter(Boolean)
  }));
  myData.newPlaces = [...(myData.newPlaces || []), ...newPlaces];
  myData.nextToken = page.nextPageToken || null;
}

myData.pagesRemaining = Math.max(0, (myData.pagesRemaining || 1) - 1);

if (myData.newPlaces.length > myData.maxResults) {
  myData.newPlaces = myData.newPlaces.slice(0, myData.maxResults);
}

const hasMore = !!myData.nextToken && myData.pagesRemaining > 0;

return [{ json: { has_more: hasMore, place_count: myData.newPlaces.length, next_page_token: myData.nextToken, text_query: myData.textQuery } }];

const execId = $execution.id;
const store = $getWorkflowStaticData('global');
const myData = store[execId] || {};
const newPlaces = myData.newPlaces || [];

const existingIds = new Set(
  $input.all()
    .map(item => item.json.place_id)
    .filter(Boolean)
);

const toProcess = newPlaces.filter(p => !existingIds.has(p.place_id));

if (toProcess.length === 0) {
  return [{ json: { __skip: true } }];
}

return toProcess.map(p => ({ json: p }));

const execId = $execution.id;
const store = $getWorkflowStaticData('global');
const myData = store[execId] || {};
if (!myData.results) myData.results = [];

const lead = { ...$input.first().json, found_at: new Date().toISOString() };

myData.results.push(lead);
return [{ json: lead }];

const execId = $execution.id;
const store = $getWorkflowStaticData('global');
const myData = store[execId] || {};
if (!myData.results) myData.results = [];

const res = $input.first().json;
let email = '', key_person = '', facebook = '', instagram = '', twitter = '', description = '';

const html = typeof res.body === 'string' ? res.body : '';
if (html.length > 100) {
  const ldBlocks = html.match(/<script[^>]+type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi) || [];
  for (const block of ldBlocks) {
    const inner = block.replace(/<script[^>]*>|<\/script>/gi, '').trim();
    try {
      const ld = JSON.parse(inner);
      const items = Array.isArray(ld) ? ld : [ld];
      for (const item of items) {
        if (!email && item.email) email = item.email;
        if (!description && item.description) description = String(item.description).trim().substring(0, 300);
        if (item.sameAs) {
          const sameAs = Array.isArray(item.sameAs) ? item.sameAs : [item.sameAs];
          for (const url of sameAs) {
            if (!facebook && /facebook\.com/i.test(url)) facebook = url;
            if (!instagram && /instagram\.com/i.test(url)) instagram = url;
            if (!twitter && /(twitter|x)\.com/i.test(url)) twitter = url;
          }
        }
        if (!key_person) {
          const candidate = item.founder || item.employee || item.author;
          if (candidate) {
            const name = typeof candidate === 'string' ? candidate
              : (Array.isArray(candidate) ? candidate[0]?.name : candidate.name);
            if (name && typeof name === 'string' && /^[A-Z]/.test(name)) key_person = name;
          }
        }
      }
    } catch(e) {}
  }

  if (!email) {
    const mailto = html.match(/href=["']mailto:([^"'?\s]+)/i);
    if (mailto) email = mailto[1];
  }
  if (!email) {
    const emails = (html.match(/[\w.+%-]+@[\w-]+\.[a-zA-Z]{2,}/g) || [])
      .filter(e => !/(png|jpg|gif|svg|css|js)$/i.test(e) && !/\d{4,}/.test(e));
    email = emails[0] || '';
  }

  if (!facebook) {
    const fb = html.match(/href=["'](https?:\/\/(?:www\.)?facebook\.com\/(?!sharer|share\.|tr[?\/])[\w.%-]+)/i);
    if (fb) facebook = fb[1].split(/["'<>\s]/)[0];
  }
  if (!instagram) {
    const ig = html.match(/href=["'](https?:\/\/(?:www\.)?instagram\.com\/[\w.]+)/i);
    if (ig) instagram = ig[1].split(/["'<>\s]/)[0];
  }
  if (!twitter) {
    const tw = html.match(/href=["'](https?:\/\/(?:www\.)?(?:twitter|x)\.com\/(?!share|intent)[\w]+)/i);
    if (tw) twitter = tw[1].split(/["'<>\s]/)[0];
  }

  if (!description) {
    const desc = html.match(/<meta[^>]+name=["']description["'][^>]+content=["']([^"']{10,})/i)
              || html.match(/<meta[^>]+content=["']([^"']{10,})["'][^>]+name=["']description/i);
    if (desc) description = desc[1].trim().substring(0, 300);
  }

  if (!key_person) {
    const person = html.match(/(?:Owner|CEO|Founder|President|Director|Principal)[^<]{0,50}?([A-Z][a-z]+ [A-Z][a-z]+)/);
    if (person) key_person = person[1];
  }
}

if (myData.results.length > 0) {
  const last = myData.results[myData.results.length - 1];
  if (!key_person) {
    const reviews = Array.isArray(last.reviews) ? last.reviews : [];
    for (const review of reviews) {
      const lower = review.toLowerCase();
      const triggers = ['owner ', 'founded by ', 'owned by ', 'run by ', 'managed by '];
      for (const trigger of triggers) {
        const idx = lower.indexOf(trigger);
        if (idx !== -1) {
          const after = review.slice(idx + trigger.length).trim();
          const nm = after.match(/^([A-Z][a-z]+ [A-Z][a-z]+)/);
          if (nm) { key_person = nm[1]; break; }
        }
      }
      if (key_person) break;
    }
  }
  last.email = email;
  last.key_person = key_person;
  last.facebook = facebook || last.facebook || '';
  last.instagram = instagram || last.instagram || '';
  last.twitter = twitter || last.twitter || '';
  last.description = description;
  delete last.reviews;
  return [{ json: { ...last } }];
}

return [{ json: {} }];

const execId = $execution.id;
const store = $getWorkflowStaticData('global');
const myData = store[execId] || {};
const leads = myData.results || [];

delete store[execId];

return [{ json: { leads, count: leads.length } }];

const leads = $input.first().json.leads || [];
const sheetId = $('Read Config').first().json.sheetId;
const columns = [
  'place_id','name','address','phone','website','business_status',
  'opening_hours','price_level','rating','user_ratings_total','types','found_at'
];
const values = leads.map(lead => columns.map(col => String(lead[col] ?? '')));
return [{ json: { values, sheet_id: sheetId } }];
